<script lang="ts">
  import { onMount } from 'svelte';

  const mean = 0.575;
  const std = 0.286;

  type Rollout = {
    label: string;
    name: string;
    reward: number;
    tokens: string[];
    advantage: number;
  };

  const rollouts: Rollout[] = [
    {
      label: 'B',
      name: 'Royal Red',
      reward: 0.9,
      tokens: ['Royal', ' Red'],
      advantage: 1.14,
    },
    {
      label: 'C',
      name: 'Rose Gold',
      reward: 0.2,
      tokens: ['Rose', ' Gold'],
      advantage: -1.31,
    },
  ];

  let idx = $state(0);
  let applied = $state(false);

  let current = $derived(rollouts[idx]);

  const wait = (ms: number) => new Promise((r) => setTimeout(r, ms));

  onMount(() => {
    let alive = true;
    const loop = async () => {
      await wait(1100);
      while (alive) {
        applied = true;
        await wait(3400);
        if (!alive) break;
        applied = false;
        await wait(900);
        if (!alive) break;
        idx = (idx + 1) % rollouts.length;
        await wait(1100);
      }
    };
    loop();
    return () => {
      alive = false;
    };
  });

  const format = (a: number) => (a > 0 ? '+' : '') + a.toFixed(2);
</script>

<figure class="apply">
  <div
    class="row"
    class:above={current.advantage > 0}
    class:below={current.advantage < 0}
  >
    <span class="chip">
      <span class="chip-label">{current.label}</span>
      <span class="chip-sep">·</span>
      <span class="chip-name">{current.name}</span>
    </span>

    <span class="arrow-right" aria-hidden="true"></span>

    <span class="tokens">
      {#each current.tokens as tok, i (i)}
        <span class="token" class:pushed={applied} style:transition-delay="{i * 90}ms">
          {tok}
        </span>
      {/each}
    </span>

    <span class="advantage">
      <span class="adv-label">advantage</span>
      <span class="adv-value">{format(current.advantage)}</span>
    </span>
  </div>

  <div class="formula">
    <div class="formula-line formula-generic">
      advantage = (reward − mean) ÷ std
    </div>
    <div class="formula-line formula-specific">
      = ({current.reward.toFixed(2)} − {mean.toFixed(2)}) ÷ {std.toFixed(2)} = <span
        class="result">{format(current.advantage)}</span
      >
    </div>
  </div>
</figure>

