<script lang="ts">
  import { flip } from 'svelte/animate';
  import { fade } from 'svelte/transition';
  import { onMount } from 'svelte';

  type Rollout = { label: string; name: string; reward: number };

  const initialOrder: Rollout[] = [
    { label: 'A', name: 'Coral Pink', reward: 0.4 },
    { label: 'B', name: 'Royal Red', reward: 0.9 },
    { label: 'C', name: 'Rose Gold', reward: 0.2 },
    { label: 'D', name: 'Ruby Red', reward: 0.8 },
  ];

  const avg = initialOrder.reduce((s, r) => s + r.reward, 0) / initialOrder.length;
  const sortedOrder = [...initialOrder].sort((a, b) => b.reward - a.reward);

  let rollouts = $state<Rollout[]>(initialOrder);
  let showScores = $state(false);
  let showAvg = $state(false);
  let ranked = $state(false);

  const wait = (ms: number) => new Promise((r) => setTimeout(r, ms));

  onMount(() => {
    let alive = true;

    const loop = async () => {
      while (alive) {
        // forward (slow, staged)
        await wait(1100);
        if (!alive) break;
        showScores = true;
        await wait(900);
        if (!alive) break;
        showAvg = true;
        await wait(1400);
        if (!alive) break;
        ranked = true;
        rollouts = sortedOrder;
        await wait(2800); // dwell

        // reverse (quick)
        if (!alive) break;
        ranked = false;
        rollouts = initialOrder;
        await wait(600);
        if (!alive) break;
        showAvg = false;
        await wait(300);
        if (!alive) break;
        showScores = false;
        await wait(500);
      }
    };

    loop();
    return () => {
      alive = false;
    };
  });
</script>

<figure class="rank">
  <div class="rollouts">
    {#each rollouts as r, i (r.label)}
      <div
        class="row"
        class:above={ranked && r.reward > avg}
        class:below={ranked && r.reward < avg}
        animate:flip={{ duration: 550 }}
      >
        <span class="chip">
          <span class="label">{r.label}</span>
          <span class="sep">·</span>
          <span class="name">{r.name}</span>
        </span>
        {#if showScores}
          <span
            class="reward"
            in:fade={{ duration: 300, delay: i * 140 }}
            out:fade={{ duration: 200 }}
          >
            {r.reward.toFixed(1)}
          </span>
        {/if}
      </div>
    {/each}
  </div>

  <div class="avg" style:opacity={showAvg ? 1 : 0}>
    average: {avg.toFixed(2)}
  </div>
</figure>

